long long solve(vector<long long> nums) {
    vector<long long> sorted_abs;
    for (long long num : nums) {
        sorted_abs.push_back(abs(num));
    }
    sort(sorted_abs.begin(), sorted_abs.end());
    int n = sorted_abs.size();
    long long total = 0;
    for (int i = 0; i < n; ++i) {
        long long target = 2 * sorted_abs[i];
        int left = i + 1;
        int right = n - 1;
        int res = i;
        while (left <= right) {
            int mid = (left + right) / 2;
            if (sorted_abs[mid] <= target) {
                res = mid;
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }
        total += (res - i);
    }
    return total;
}
